 				}
 				i += datalen + 1;
 				/* copy remainder of strip */
 				_TIFFmemcpy(&(buffer[*bufferoffset]), &(strip[i]), *striplength - i);
 				*bufferoffset+= *striplength - i;
 				return(1);
			default:
				/* ignore any other marker */
				break;
