    header->biPlanes |= (OPJ_UINT16)((OPJ_UINT32)getc(IN) << 8);

     header->biBitCount  = (OPJ_UINT16)getc(IN);
     header->biBitCount |= (OPJ_UINT16)((OPJ_UINT32)getc(IN) << 8);

